/* ============================================================================
   SQL Server 2025 as a Vector Store — Semantic Search in pure T-SQL (SSMS / VS Code)
   Day of Data BR Pre-Con · "AI for the Rest of Us"

   No app, no Python, no API key. The WorkshopCatalog.Products table already has a
   VECTOR(384) column (DescriptionEmbedding) we filled in this morning. Here we search
   it BY MEANING with SQL Server 2025's native VECTOR_DISTANCE — as ordinary SQL.

   The query vectors below are pre-computed embeddings of a plain-English phrase.
   ============================================================================ */
USE WorkshopCatalog;
GO

/* ---------------------------------------------------------------------------
   1) The OLD way — keyword search. Nobody's product literally says "waterproof".
   --------------------------------------------------------------------------- */
SELECT CAST(Name AS VARCHAR(28)) AS Name, CAST(Category AS VARCHAR(11)) AS Category
FROM Products
WHERE Name LIKE '%waterproof%' OR Description LIKE '%waterproof%';   -- -> 0 rows
GO

