SELECT TOP 3
    CAST(Name AS VARCHAR(26))            AS Name,
    CAST(Category AS VARCHAR(11))        AS Category,
    Price,
    CAST(LEFT(Description, 74) AS VARCHAR(74)) AS Why_it_matched,
    CAST(VECTOR_DISTANCE('cosine', DescriptionEmbedding, @jacket) AS DECIMAL(5,3)) AS distance
FROM Products ORDER BY distance;   -- smaller distance = closer in meaning
GO

